MuJoCo

Usage Example: Simulation
Once you have installed mujoco in python, put the code below in a file and then run this command from the command line:
python3 &lt;filename where you placed code below&gt;
If you use macOS, the use of mujoco.viewer for visualization requires a different command:
mjpython &lt;filename where you placed code below&gt;
import mujoco
import mujoco.viewer
import time 

# Load a model from a file (won't do this here to avoid external file calls)
# model = mujoco.MjModel.from_xml_path('path/to/your/model.xml')

# Create a simple pendulum model from a string containing that xml
model = mujoco.MjModel.from_xml_string("""
&lt;mujoco&gt;
  &lt;asset&gt;
    &lt;texture name="skybox" type="skybox" builtin="gradient" rgb1=".3 .5 .7" rgb2="0 0 0" width="100" height="100"/&gt;
  &lt;/asset&gt;

  &lt;worldbody&gt;
    &lt;light name="light1" pos="0.3 0.3 1"/&gt;
    &lt;geom name="ground" type="plane" size="1 1 0.1" rgba="0.8 0.8 0.8 1"/&gt;

    &lt;body name="pendulum" pos="0 0 0"&gt;
      &lt;joint name="pivot" type="hinge" pos="0 0 0" axis="0 1 0" damping="0.1"/&gt;
      &lt;geom name="rod" type="capsule" fromto="0 0 0 0 0 1" size="0.05" rgba="0.5 0.5 0.5 1"/&gt;
      &lt;geom name="mass" type="sphere" pos="0 0 1" size="0.1" rgba="0.8 0.2 0.2 1"/&gt;
    &lt;/body&gt;
  &lt;/worldbody&gt;
&lt;/mujoco&gt;
""")

## Set the time step, initial condition
dt: float = 0.002
model.opt.timestep = dt
data = mujoco.MjData(model)
data.qpos[0]=0.01

# Create a viewer
viewer = mujoco.viewer.launch_passive(model, data)
# Run a viewer with simulation in 'real-time'
try: 
    while viewer.is_running():
        step_start = time.time()
        # Step the simulation
        mujoco.mj_step(model, data)
        # Update the viewer
        viewer.sync()
        # Add a small delay to control frame rate
        time_until_next_step = dt - (time.time() - step_start)
        if time_until_next_step &gt; 0:
            time.sleep(time_until_next_step)
except KeyboardInterrupt:
    print("Viewer closed by user")
finally:
    viewer.close()
